# 格式化要发送的消息
def format_b4_send(content):
    arr = []
    for ch in content:
        tmp = ''.join(list(map(lambda x: hex(ord(x)), ch)))
        if int(tmp, 16) > 0xff:
            tmp = tmp[2:]
            high = int((tmp[0] + tmp[1]), 16)
            low = int((tmp[2] + tmp[3]), 16)
            arr.append(low)
            arr.append(high)
        else:
            high = 0
            low = int((tmp[2] + tmp[3]), 16)
            arr.append(low)
            arr.append(high)
    return arr


# 获取ip
def get_ip(ip):
    target_host = []
    if ip.find('.') == -1:
        logger('\nYou enter a error IP.')
        logger("Please enter the correct format of the IP again.")
        return
    if ip.find('-') != -1:
        ip_arr = ip.split('-')
        ip_arrs = ip_arr[0].split('.')
        if int(ip_arr[1]) > 254:
            ip_arr[1] = '254'
        for i in range(int(ip_arrs[3]), int(ip_arr[1])+1):
            ip_arrs[3] = str(i)
            target_host.append('.'.join(ip_arrs))
    elif ip.find('/') == -1:
        target_host.append(ip)
    elif ip.find('/24') != -1:
        ip_arr = ip.split('/')
        ip_arrs = ip_arr[0].split('.')
        for i in range(1, 255):
            ip_arrs[3] = str(i)
            target_host.append('.'.join(ip_arrs))
    else:
        logger('\nYou enter a error IP.')
        logger("Please enter the correct format of the IP again.")
        return
    return target_host


